21	// newInstallCommand creates the "ddx install <name>" command.
22	func (f *CommandFactory) newInstallCommand() *cobra.Command {
23		cmd := &cobra.Command{
24			Use:   "install <name>",
25			Short: "Install a package or resource",
26			Long: `Install a package or resource from the DDx registry into the
27	current project under .ddx/plugins/<name>/.
28	
29	Examples:
30	  ddx install helix                        # Install HELIX workflow
31	  ddx install helix --force                # Reinstall even if already up to date
32	  ddx install persona/strict-code-reviewer # Install a single persona`,
33			Args: cobra.ExactArgs(1),
34			RunE: f.runInstall,
35		}
36		cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
37		cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
38		return cmd
39	}
40	
41	func (f *CommandFactory) runInstall(cmd *cobra.Command, args []string) error {
42		out := cmd.OutOrStdout()
43		force, _ := cmd.Flags().GetBool("force")
44		name := args[0]
45	
46		// Ensure install operations resolve relative paths against the project
47		// root (WorkingDir), not the caller's cwd. This prevents creating stale
48		// .ddx/ workspaces in subdirectories.
49		if f.WorkingDir != "" {
50			origDir, _ := os.Getwd()
51			if origDir != f.WorkingDir {
52				if err := os.Chdir(f.WorkingDir); err == nil {
53					defer func() { _ = os.Chdir(origDir) }()
54				}
55			}
56		}
57	
58		// Handle --local: install from a local directory instead of registry.
59		if localPath, _ := cmd.Flags().GetString("local"); localPath != "" {
60			return f.installLocal(name, localPath, force, out)
61		}
62	
63		if registry.IsResourcePath(name) {
64			// Individual resource install (e.g. "persona/strict-code-reviewer")
65			fmt.Fprintf(out, "Installing resource %s...\n", name)
66			entry, err := registry.InstallResource(name)
67			if err != nil {
68				return fmt.Errorf("install resource: %w", err)
69			}
70	
71			state, err := registry.LoadState()
72			if err != nil {
73				return fmt.Errorf("loading state: %w", err)
74			}
75			state.AddOrUpdate(entry)
76			if err := registry.SaveState(state); err != nil {
77				return fmt.Errorf("saving state: %w", err)
78			}
79	
80			fmt.Fprintf(out, "Installed %s\n", name)
81			return nil
82		}
83	
84		// Package install (e.g. "helix")
85		reg := registry.BuiltinRegistry()
86		pkg, err := reg.Find(name)
87		if err != nil {
88			return err
89		}
90	
91		// Fetch actual latest version from GitHub (overrides hardcoded registry version).
92		if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
93			pkg.Version = strings.TrimPrefix(release.TagName, "v")
94		}
95	
96		// Check if already installed at the latest version.
97		state, err := registry.LoadState()
98		if err == nil {
99			for _, e := range state.Installed {
100				if e.Name == name {
101					if e.Version == pkg.Version {
102						if !force {
103							fmt.Fprintf(out, "%s %s is already up to date\n", e.Name, e.Version)
104							return nil
105						}
106						fmt.Fprintf(out, "Reinstalling %s %s...\n", e.Name, e.Version)
107					} else {
108						fmt.Fprintf(out, "Updating %s from %s to %s...\n", e.Name, e.Version, pkg.Version)
109					}
110				}
111			}
112		}
113	
114		// Capture old file list before installing so we can remove stale files.
115		var oldFiles []string
116		if state != nil {
117			if old := state.FindInstalled(name); old != nil {
118				oldFiles = append([]string{}, old.Files...)
119			}
120		}
121	
122		fmt.Fprintf(out, "Installing %s %s from %s...\n", pkg.Name, pkg.Version, pkg.Source)
123	
124		entry, err := registry.InstallPackage(pkg, f.WorkingDir)
125		if err != nil {
126			return fmt.Errorf("install package: %w", err)
127		}
128	
129		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
130		if removed > 0 {
131			fmt.Fprintf(out, "Removed %d stale file(s)\n", removed)
132		}
133	
134		state, stateErr := registry.LoadState()
135		if stateErr != nil {
136			return fmt.Errorf("loading state: %w", stateErr)
137		}
138		state.AddOrUpdate(entry)
139		if err := registry.SaveState(state); err != nil {
140			return fmt.Errorf("saving state: %w", err)
141		}
142	
143		fmt.Fprintf(out, "Installed %s %s (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))
144	
145		// Auto-commit skill symlinks and other trackable changes.
146		commitPluginChanges(name, pkg.Version)
147	
148		return nil
149	}
