151	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
152		if len(oldFiles) == 0 {
153			return 0
154		}
155	
156		newSet := make(map[string]bool, len(newFiles))
157		for _, f := range newFiles {
158			newSet[f] = true
159		}
160	
161		removed := 0
162		for _, f := range oldFiles {
163			if newSet[f] {
164				continue
165			}
166			expanded := registry.ExpandHome(f)
167			if err := os.RemoveAll(expanded); err == nil {
168				removed++
169			}
170		}
171		return removed
172	}
