174	// commitPluginChanges stages and commits plugin-related changes in the working tree.
175	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
176	func commitPluginChanges(name, version string) {
177		// Stage the project-local plugin tree and the skill copies.
178		paths := []string{
179			filepath.Join(".ddx", "plugins", name) + string(filepath.Separator),
180			".agents/skills/",
181			".claude/skills/",
182		}
183		ctx := context.Background()
184		for _, p := range paths {
185			if _, err := os.Stat(p); err == nil {
186				gitAdd := internalgit.Command(ctx, "", "add", p)
187				_ = gitAdd.Run()
188			}
189		}
190	
191		// Check if there's anything to commit.
192		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
193		if status.Run() == nil {
194			return // nothing staged
195		}
196	
197		msg := fmt.Sprintf("chore: install %s %s", name, version)
198		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
199		_ = gitCommit.Run()
200	}
