217	// installLocal installs a plugin from a local directory into the project
218	// under .ddx/plugins/<name>/. The plugin tree is copied — never symlinked
219	// out to a developer checkout. Skills are routed through skills.Install
220	// (real-file copies into .agents/skills/ + .claude/skills/).
221	func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
222		// Resolve to absolute path.
223		absPath, err := filepath.Abs(localPath)
224		if err != nil {
225			return fmt.Errorf("resolving path %s: %w", localPath, err)
226		}
227		if _, err := os.Stat(absPath); os.IsNotExist(err) {
228			return fmt.Errorf("local path does not exist: %s", absPath)
229		}
230	
231		// Load package.yaml when present so local installs honor the manifest
232		// contract, but keep the built-in registry as a compatibility fallback.
233		reg := registry.BuiltinRegistry()
234		fallbackPkg, _ := reg.Find(name)
235	
236		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
237		if manifestErr == nil {
238			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
239				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
240			}
241		} else {
242			if os.IsNotExist(manifestErr) && manifestMissing {
243				if pkg == nil {
244					pkg = &registry.Package{
245						Name:        name,
246						Version:     "local",
247						Description: "local plugin package",
248						Type:        registry.PackageTypePlugin,
249						Source:      absPath,
250					}
251				}
252			} else if len(manifestIssues) > 0 {
253				return fmt.Errorf("validating package manifest: %w", manifestErr)
254			} else {
255				return fmt.Errorf("loading package manifest: %w", manifestErr)
256			}
257		}
258	
259		if pkg == nil {
260			pkg = &registry.Package{
261				Name:        name,
262				Version:     "local",
263				Description: "local plugin package",
264				Type:        registry.PackageTypePlugin,
265				Source:      absPath,
266			}
267		}
268	
269		if pkg.Install.Root == nil {
270			pkg.Install.Root = &registry.InstallMapping{
271				Source: ".",
272				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
273			}
274		}
275	
276		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
277			return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
278		}
279	
280		if issues := registry.ValidatePackageStructure(absPath, pkg); len(issues) > 0 {
281			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
282		}
283	
284		pluginDir := pkg.Install.Root.Target
285	
286		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
287			return err
288		}
289	
290		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
291			return fmt.Errorf("creating plugins dir: %w", err)
292		}
293	
294		// Copy the plugin tree into the project. No symlinks back to the
295		// developer's checkout — the project owns its own copy.
296		written, err := copyDirTree(absPath, pluginDir)
297		if err != nil {
298			return fmt.Errorf("copying plugin into %s: %w", pluginDir, err)
299		}
300	
301		fmt.Fprintf(out, "Installed %s -> %s\n", absPath, pluginDir)
302	
303		entry := registry.InstalledEntry{
304			Name:    pkg.Name,
305			Version: pkg.Version,
306			Type:    pkg.Type,
307			Source:  absPath,
308		}
309		entry.Files = append(entry.Files, written...)
310	
311		// Install skills via the shared installer.
312		if len(pkg.Install.Skills) > 0 {
313			absPlugin, _ := filepath.Abs(pluginDir)
314			absProject := f.WorkingDir
315			if absProject == "" {
316				absProject, _ = os.Getwd()
317			}
318			if !filepath.IsAbs(absProject) {
319				absProject, _ = filepath.Abs(absProject)
320			}
321			if err := skills.Install(os.DirFS(absPlugin), absProject, skills.Options{Force: force}); err != nil {
322				return fmt.Errorf("installing skills: %w", err)
323			}
324			// Record skill dirs by name for state tracking.
325			for _, candidate := range []string{
326				filepath.Join(absPlugin, ".agents", "skills"),
327				filepath.Join(absPlugin, "skills"),
328			} {
329				if entries, derr := os.ReadDir(candidate); derr == nil {
330					for _, e := range entries {
331						for _, sub := range []string{".agents/skills", ".claude/skills"} {
332							entry.Files = append(entry.Files, filepath.Join(filepath.FromSlash(sub), e.Name()))
333						}
334					}
335					if len(entries) > 0 {
336						break
337					}
338				}
339			}
340		}
341	
342		// Copy CLI script if defined (skip if target is a developer symlink).
343		if pkg.Install.Scripts != nil {
344			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
345			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
346				target, _ := os.Readlink(dst)
347				fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
348				entry.Files = append(entry.Files, dst)
349			} else {
350				copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
351				if err != nil {
352					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
353				} else {
354					entry.Files = append(entry.Files, copied)
355				}
356			}
357		}
358	
359		// Set execute bits on installed plugin files.
360		for _, rel := range pkg.Install.Executable {
361			p := filepath.Join(pluginDir, filepath.FromSlash(rel))
362			if info, err := os.Stat(p); err == nil && !info.IsDir() {
363				_ = os.Chmod(p, info.Mode()|0111)
364			}
365		}
366	
367		// Save install state.
368		state, _ := registry.LoadState()
369		if state == nil {
370			state = &registry.InstalledState{}
371		}
372		entry.InstalledAt = time.Now()
373		state.AddOrUpdate(entry)
374		if err := registry.SaveState(state); err != nil {
375			return fmt.Errorf("saving state: %w", err)
376		}
377	
378		fmt.Fprintf(out, "Installed %s (local) — %d file(s)\n", entry.Name, len(entry.Files))
379		commitPluginChanges(entry.Name, entry.Version)
380		return nil
381	}
