431	// newInstalledCommand creates the "ddx installed" command.
432	func (f *CommandFactory) newInstalledCommand() *cobra.Command {
433		return &cobra.Command{
434			Use:   "installed",
435			Short: "List installed packages",
436			Long:  `List all packages and resources installed via ddx install.`,
437			Args:  cobra.NoArgs,
438			RunE:  f.runInstalled,
439		}
440	}
