442	func (f *CommandFactory) runInstalled(cmd *cobra.Command, args []string) error {
443		out := cmd.OutOrStdout()
444	
445		state, err := registry.LoadState()
446		if err != nil {
447			return fmt.Errorf("loading state: %w", err)
448		}
449	
450		if len(state.Installed) == 0 {
451			fmt.Fprintln(out, "No packages installed.")
452			return nil
453		}
454	
455		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
456		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tSTATUS\tINSTALLED")
457		for _, e := range state.Installed {
458			status := "ok"
459			if !e.VerifyFiles() {
460				status = "BROKEN"
461			}
462			fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n",
463				e.Name,
464				e.Version,
465				string(e.Type),
466				status,
467				e.InstalledAt.Format("2006-01-02"),
468			)
469		}
470		return w.Flush()
471	}
