473	// newUninstallCommand creates the "ddx uninstall <name>" command.
474	func (f *CommandFactory) newUninstallCommand() *cobra.Command {
475		return &cobra.Command{
476			Use:   "uninstall <name>",
477			Short: "Remove an installed package",
478			Long:  `Remove a package or resource installed via ddx install.`,
479			Args:  cobra.ExactArgs(1),
480			RunE:  f.runUninstall,
481		}
482	}
