484	func (f *CommandFactory) runUninstall(cmd *cobra.Command, args []string) error {
485		name := args[0]
486		out := cmd.OutOrStdout()
487	
488		state, err := registry.LoadState()
489		if err != nil {
490			return fmt.Errorf("loading state: %w", err)
491		}
492	
493		entry := state.FindInstalled(name)
494		if entry == nil {
495			return fmt.Errorf("package %q is not installed", name)
496		}
497	
498		if err := registry.UninstallPackage(entry); err != nil {
499			return fmt.Errorf("uninstall: %w", err)
500		}
501	
502		state.Remove(name)
503		if err := registry.SaveState(state); err != nil {
504			return fmt.Errorf("saving state: %w", err)
505		}
506	
507		fmt.Fprintf(out, "Uninstalled %s\n", name)
508		return nil
509	}
