594	func (f *CommandFactory) runSearch(cmd *cobra.Command, args []string) error {
595		query := args[0]
596		out := cmd.OutOrStdout()
597	
598		reg := registry.BuiltinRegistry()
599		results := reg.Search(query)
600	
601		if len(results) == 0 {
602			fmt.Fprintf(out, "No packages found matching %q\n", query)
603			return nil
604		}
605	
606		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
607		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tDESCRIPTION")
608		for _, pkg := range results {
609			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n",
610				pkg.Name,
611				pkg.Version,
612				string(pkg.Type),
613				pkg.Description,
614			)
615		}
616		return w.Flush()
617	}
