87			expanded := ExpandHome(f)
88			if _, err := os.Stat(expanded); err == nil {
89				return true
90			}
91			// Check if it's a symlink that resolves
92			if info, err := os.Lstat(expanded); err == nil && info.Mode()&os.ModeSymlink != 0 {
